mapper.select:
SELECT date_trunc('hour', create_time) AS bucket, COUNT(*) AS count
  FROM (
      SELECT create_time FROM dc3_device_event
       WHERE deleted = 0 AND tenant_id = #{tenantId} AND create_time >= #{from}
      UNION ALL
      SELECT create_time FROM dc3_driver_event
       WHERE deleted = 0 AND tenant_id = #{tenantId} AND create_time >= #{from}
  ) merged
 GROUP BY bucket
 ORDER BY bucket ASC
